wire [2:0] shift_amount;
wire [7:0] VALUE_TO_SHIFT = 8'h9C;
assign shift_amount = 3'b000 - 1'b1;
assign shift_result_lsb = VALUE_TO_SHIFT >> shift_amount;

localparam [7:0] ADDITION_CONSTANT = 8'hA0;
wire [2:0] truncated_add_result;
assign truncated_add_result = $unsigned(ADDITION_CONSTANT + 1'b1);

wire [2:0] truncated_result;
wire [2:0] shift_amount;
assign truncated_result = 3'b001;
assign shift_amount = truncated_result - 1'b1;
